SELECT id, slug, score, created_at, category_slug, author_username, title, description, image_path, tags FROM list_memes_flat(#{locale}::locale_code) WHERE 1=1
AND category_slug = #{category}
ORDER BY
title ASC NULLS LAST, id DESC created_at DESC NULLS LAST, id DESC score DESC, id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM list_memes_flat(#{locale}::locale_code)
WHERE 1=1

    AND category_slug = #{category}
